  focus: "Tani që ke bazat, do të ndërtosh fjali më të gjata për situata reale në udhëtim. Sot lidh arsye, kohë dhe kërkesa.",
  vocab: [{ hi: "क्योंकि", sq: "sepse", ipa: "kyon-ki" }, { hi: "लेकिन", sq: "por", ipa: "le-kin" }, { hi: "और", sq: "dhe", ipa: "aur" }, { hi: "या", sq: "ose", ipa: "ya" }, { hi: "पहले", sq: "më parë", ipa: "pə-hle" }, { hi: "बाद में", sq: "më vonë", ipa: "baad men" }, { hi: "ज़रूरत", sq: "nevojë", ipa: "zə-ru-rət" }, { hi: "थोड़ा", sq: "pak", ipa: "tho-ra" }, { hi: "अभी", sq: "tani", ipa: "ə-bhi" }],
  phrases: [{ hi: "मुझे अभी मदद चाहिए।", sq: "Më duhet ndihmë tani.", ipa: "muj-he ə-bhi mə-dəd cha-hi-ye" }, { hi: "मैं थका हूँ, लेकिन ठीक हूँ।", sq: "Jam i lodhur, por jam mirë.", ipa: "main thə-ka hun le-kin thik hun" }, { hi: "पहले होटल, बाद में बाज़ार।", sq: "Së pari hoteli, më vonë tregu.", ipa: "pə-hle ho-təl baad men baa-zaar" }, { hi: "मुझे पानी और खाना चाहिए।", sq: "Më duhet ujë dhe ushqim.", ipa: "muj-he paa-ni aur kha-na cha-hi-ye" }, { hi: "मैं नहीं जा सकता क्योंकि देर हो गई।", sq: "Nuk mund të shkoj sepse u bë vonë.", ipa: "main nə-hin ja sək-ta kyon-ki der ho gə-i" }],
  grammar: "Fjalët lidhëse të bëjnë të tingëllosh më natyrshëm. “और” është “dhe”, “लेकिन” është “por”, “क्योंकि” është “sepse”. Vendosi mes frazave të thjeshta për të krijuar mendime më të plota.",
  practice: ["Bashko dy fjali me “और”.", "Bashko dy fjali me “लेकिन”.", "Jep një arsye duke përdorur “क्योंकि”.", "Thuaj një plan me “पहले” dhe “बाद में”.", "Shkruaj pesë fjali udhëtimi më të gjata."]
